const $ = (selector, root = document) => root.querySelector(selector);
const $$ = (selector, root = document) => [...root.querySelectorAll(selector)];
const state = { settings: {}, bikes: [], promotions: [], accessories: [], filter: 'all', query: '', session: null, currentChat: null, chats: [], chatBellEnabled: false, lastUnread: 0, poller: null };
const statusLabel = { in_stock: 'Còn hàng', incoming: 'Sắp về', reserved: 'Đang giữ xe', sold: 'Đã bán' };
const categoryLabel = { new: 'Xe mới', used: 'Xe cũ' };
const money = value => Number(value || 0).toLocaleString('vi-VN') + 'đ';
const esc = value => String(value ?? '').replace(/[&<>'"]/g, char => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;' }[char]));
const normalize = value => String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/đ/g, 'd').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
function editDistance(a,b) {
  const x = String(a || ''), y = String(b || '');
  if (x === y) return 0;
  if (!x) return y.length;
  if (!y) return x.length;
  const row = Array.from({length: y.length + 1}, (_, i) => i);
  for (let i = 1; i <= x.length; i++) {
    let previous = row[0]; row[0] = i;
    for (let j = 1; j <= y.length; j++) {
      const saved = row[j];
      row[j] = Math.min(row[j] + 1, row[j - 1] + 1, previous + (x[i - 1] === y[j - 1] ? 0 : 1));
      previous = saved;
    }
  }
  return row[y.length];
}
function nearMatch(query, text) {
  const q = normalize(query); const t = normalize(text);
  if (!q) return true;
  if (t.includes(q)) return true;
  const haystack = t.split(/\s+/).filter(Boolean);
  return q.split(/\s+/).every(part => haystack.some(word => {
    if (word.startsWith(part) || word.includes(part)) return true;
    const allowance = part.length <= 4 ? 1 : part.length <= 7 ? 2 : 3;
    return editDistance(part, word) <= allowance;
  }));
}
async function api(path, options = {}) { const response = await fetch(path, { ...options, headers: { ...(options.headers || {}), ...(options.body && !(options.body instanceof FormData) && !options.headers?.['content-type'] ? { 'content-type': 'application/json' } : {}) } }); const data = await response.json().catch(() => ({})); if (!response.ok) throw new Error(data.error || 'Có lỗi xảy ra.'); return data; }
function setHtmlLines(element, text) { if (element) element.innerHTML = esc(text || '').replace(/\n/g, '<br>'); }
function getPathMode() { const path = location.pathname.replace(/\/$/, '') || '/'; if (path === '/admin') return 'admin'; if (path === '/tra-gop') return 'finance'; return 'home'; }
