  Object.entries(socialMap).forEach(([id, link]) => { const element = $('#' + id); if (!element) return; element.href = link || '#'; element.classList.toggle('is-disabled', !link); element.onclick = !link ? event => { event.preventDefault(); alert('Kênh này đang được cập nhật.'); } : null; });
