  return `<button type="button" class="related-bike" data-related-bike="${bike.id}"><span class="related-bike-image"><img src="${esc(image)}" alt="${esc(bike.name)}" loading="lazy" /></span><span><small>${esc(bike.brand || 'Xe máy')} • ${categoryLabel[bike.category] || 'Xe'}</small><b>${esc(bike.name)}</b>${bike.show_price && Number(bike.price) ? `<em>${money(bike.price)}</em>` : '<em>Liên hệ báo giá</em>'}</span><i>→</i></button>`;
