function openGalleryViewer(images, index, alt) { if (!images?.length) return; state.galleryViewer = {images:[...images],index:Number(index)||0,alt}; const viewer = ensureGalleryViewer(); viewer.hidden = false; document.body.classList.add('modal-open'); renderGalleryViewer(); }
function cycleGalleryViewer(delta) { if (!state.galleryViewer?.images?.length) return; state.galleryViewer.index += delta; renderGalleryViewer(); }
