  const form = $('[data-detail-lead]'); form.addEventListener('submit', async event => { event.preventDefault(); const button = $('button', form); const message = $('.form-message', form); const data = Object.fromEntries(new FormData(form)); data.type = 'consultation'; data.bike_name = bike.name + (variants.length ? ` • ${selectedColor()}` : ''); button.disabled=true; try { await api('/api/leads',{method:'POST',body:JSON.stringify(data)}); form.reset(); message.textContent='Tâm An đã nhận thông tin. Nhân viên sẽ liên hệ sớm.'; } catch(error){ message.textContent=error.message; } finally { button.disabled=false; } });
  openModal('detail-modal');
