async function loadPublic() { const [settings, bikes, promos, accessories] = await Promise.all([api('/api/settings'), api('/api/bikes'), api('/api/promotions'), api('/api/accessories')]); state.settings = settings.settings; state.bikes = bikes.bikes; state.promotions = promos.promotions; state.accessories = accessories.accessories; applySettings(); renderBikes(); renderPromotions(); renderAccessories(); trackVisit(); }
async function trackVisit() { try { let visitor = localStorage.getItem('tam_an_visitor'); if (!visitor) { visitor = crypto.randomUUID(); localStorage.setItem('tam_an_visitor', visitor); } await fetch('/api/analytics/view',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({ path: location.pathname, visitor_id: visitor })}); } catch {} }
function bindPublic() { $('[data-menu-toggle]')?.addEventListener('click', () => $('#main-nav').classList.toggle('open')); $$('.main-nav a').forEach(a => a.addEventListener('click', () => $('#main-nav').classList.remove('open'))); $$('.category-card').forEach(button => button.addEventListener('click', () => { state.filter = button.dataset.filterLink; state.query = ''; $('#bike-search').value = ''; $('#clear-search').hidden = true; renderBikes(); $('#xe').scrollIntoView({behavior:'smooth',block:'start'}); })); $('#bike-search')?.addEventListener('input', event => { state.query = event.target.value; $('#clear-search').hidden = !state.query; renderBikes(); }); $('#clear-search')?.addEventListener('click', () => { state.query=''; $('#bike-search').value=''; $('#clear-search').hidden=true; renderBikes(); }); $$('[data-carousel-scroll]').forEach(button => button.addEventListener('click', () => { const grid = $('#bike-grid'); grid.scrollBy({left:(button.dataset.carouselScroll === 'next' ? 1 : -1) * Math.max(280, grid.clientWidth*.76),behavior:'smooth'}); })); $$('[data-detail-close]').forEach(btn => btn.addEventListener('click', () => closeModal('detail-modal'))); $('#finance-form')?.addEventListener('submit', submitLead); const visitorNameField=$('#visitor-chat-name'); if(visitorNameField){visitorNameField.value=localStorage.getItem('tam_an_chat_name')||'';visitorNameField.addEventListener('input',()=>localStorage.setItem('tam_an_chat_name',visitorNameField.value.trim()));} $('#open-chat')?.addEventListener('click', () => { $('#chat-widget').hidden = false; refreshVisitorChat(); }); $('#chat-close')?.addEventListener('click', () => { $('#chat-widget').hidden = true; }); $('#visitor-chat-form')?.addEventListener('submit', sendVisitorChat); }
async function submitLead(event) { event.preventDefault(); const form = event.currentTarget; const message = $('#finance-message'); const data = Object.fromEntries(new FormData(form)); try { await api('/api/leads',{method:'POST',body:JSON.stringify({ ...data, type:'finance' })}); message.textContent = 'Đã gửi yêu cầu. Tâm An sẽ liên hệ lại sớm.'; form.reset(); } catch (error) { message.textContent = error.message; } }
function visitorId() { let id = localStorage.getItem('tam_an_chat_visitor'); if (!id) { id = crypto.randomUUID(); localStorage.setItem('tam_an_chat_visitor',id); } return id; }
function chatMessageMarkup(message, context='admin'){const staff=message.sender==='staff';const label=staff?(message.sender_name?`Nhân viên ${message.sender_name}`:'Nhân viên Tâm An'):(context==='visitor'?'Bạn':(message.sender_name||'Khách hàng'));return `<div class="chat-message ${staff?'staff':'visitor'}"><small>${esc(label)}</small><span>${esc(message.message)}</span></div>`;}
async function refreshVisitorChat() { if ($('#chat-widget')?.hidden) return; try { const result = await api(`/api/chat/messages?visitor_id=${encodeURIComponent(visitorId())}`); const root = $('#visitor-chat-messages'); const messages = result.messages || []; const nameField=$('#visitor-chat-name'); if(nameField&&result.conversation?.visitor_name&&!nameField.value)nameField.value=result.conversation.visitor_name; root.innerHTML = messages.length ? messages.map(message=>chatMessageMarkup(message,'visitor')).join('') : '<div class="chat-message system"><span>Chào bạn! Bạn cần tư vấn xe, trả góp hay phụ kiện? Hãy nhắn Tâm An.</span></div>'; root.scrollTop = root.scrollHeight; } catch {} }
async function sendVisitorChat(event) { event.preventDefault(); const input = $('#visitor-chat-input'); const nameField=$('#visitor-chat-name'); const text = input.value.trim(); const visitorName=(nameField?.value||localStorage.getItem('tam_an_chat_name')||'').trim(); if (!text) return; if(!visitorName){if(nameField){nameField.focus();nameField.placeholder='Vui lòng nhập tên để nhân viên hỗ trợ';}return;} try { await api('/api/chat/messages',{method:'POST',body:JSON.stringify({visitor_id:visitorId(),visitor_name:visitorName,message:text})}); localStorage.setItem('tam_an_chat_name',visitorName); input.value=''; await refreshVisitorChat(); } catch { alert('Chưa gửi được tin nhắn. Vui lòng thử lại.'); } }
function owner() { return state.session?.role === 'owner'; }
function roleText() { return owner() ? 'Chủ cửa hàng — toàn quyền' : 'Nhân viên — có thể thêm và sửa sản phẩm, không thể xoá'; }
async function initAdmin() { $('#storefront').hidden = true; $('#finance-page').hidden = true; $('#admin-shell').hidden = false; try { const me = await api('/api/auth/me'); state.session = me.session; } catch {} if (state.session?.authenticated) showAdminDashboard(); else $('#login-card').hidden = false; $('#login-form').addEventListener('submit', login); $('#logout-button')?.addEventListener('click', logout); $('#add-bike-button')?.addEventListener('click', () => openBikeForm()); $('#bike-form')?.addEventListener('submit', saveBike); $('#image-input')?.addEventListener('change', event => uploadBikeImages(event.target.files)); $('#add-color-variant')?.addEventListener('click', addColorVariant); $('#color-variants')?.addEventListener('click', handleColorVariantClick); $('#color-variants')?.addEventListener('change', handleColorVariantChange); $('#settings-form')?.addEventListener('submit', saveSettings); $('#settings-image-input')?.addEventListener('change', event => uploadSettingImage(event.target.files?.[0])); $('#settings-logo-input')?.addEventListener('change', event => uploadSettingAsset(event.target.files?.[0], 'logo_image', 'Đã tải logo. Bấm Lưu thay đổi website để áp dụng.')); $('#settings-favicon-input')?.addEventListener('change', event => uploadSettingAsset(event.target.files?.[0], 'favicon_image', 'Đã tải icon tab. Bấm Lưu thay đổi website để áp dụng.')); $('#refresh-leads')?.addEventListener('click', loadLeads); $('#add-promo-button')?.addEventListener('click', () => openPromoForm()); $('#promo-form')?.addEventListener('submit', savePromo); $('#promo-image-input')?.addEventListener('change', event => uploadSingleToField(event.target.files?.[0], '#promo-form [name="image_url"]')); $('#add-accessory-button')?.addEventListener('click', () => openAccessoryForm()); $('#accessory-form')?.addEventListener('submit', saveAccessory); $('#accessory-image-input')?.addEventListener('change', event => uploadSingleToField(event.target.files?.[0], '#accessory-form [name="image_url"]')); $('#add-staff-button')?.addEventListener('click', () => openModal('staff-modal')); $('#staff-form')?.addEventListener('submit', saveStaff); $('#refresh-analytics')?.addEventListener('click', loadAnalytics); $('#refresh-chats')?.addEventListener('click', loadChats); $('#admin-chat-form')?.addEventListener('submit', replyChat); $('#chat-ai-suggest')?.addEventListener('click', suggestAiReply); $('#chat-sound-button')?.addEventListener('click', armChatBell); $$('[data-modal-close]').forEach(el=>el.addEventListener('click',()=>closeModal('bike-modal'))); $$('[data-promo-close]').forEach(el=>el.addEventListener('click',()=>closeModal('promo-modal'))); $$('[data-accessory-close]').forEach(el=>el.addEventListener('click',()=>closeModal('accessory-modal'))); $$('[data-staff-close]').forEach(el=>el.addEventListener('click',()=>closeModal('staff-modal'))); $$('.admin-tab').forEach(button => button.addEventListener('click', () => switchAdminView(button.dataset.adminView))); }
async function login(event) { event.preventDefault(); const message = $('#login-message'); try { const username=$('#admin-username').value.trim(); const password=$('#admin-password').value; const result=await api('/api/auth/login',{method:'POST',body:JSON.stringify({username,password})}); state.session=result.session; $('#login-card').hidden=true; showAdminDashboard(); } catch(error){message.textContent=error.message;} }
async function logout() { await api('/api/auth/logout',{method:'POST'}).catch(()=>{}); state.session=null; if (state.poller) clearInterval(state.poller); location.reload(); }
function switchAdminView(view) { if (!owner() && ['site','staff','promos','analytics'].includes(view)) return; $$('.admin-tab').forEach(tab=>tab.classList.toggle('active',tab.dataset.adminView===view)); $$('.admin-view').forEach(panel=>panel.hidden=panel.dataset.adminPanel!==view); if (view==='bikes') loadAdminBikes(); if(view==='leads') loadLeads(); if(view==='promos') loadAdminPromos(); if(view==='accessories') loadAdminAccessories(); if(view==='chats') loadChats(); if(view==='analytics') loadAnalytics(); if(view==='site') loadSettingsForm(); if(view==='staff') loadStaff(); }
function showAdminDashboard() { $('#login-card').hidden=true; $('#admin-dashboard').hidden=false; $('#current-user-role').textContent=roleText(); $$('.admin-owner-only').forEach(element=>element.hidden=!owner()); if (!owner()) { const active=$('.admin-tab.active'); if (active?.dataset.adminView !== 'bikes') switchAdminView('bikes'); } loadAdminBikes(); if (state.poller) clearInterval(state.poller); state.poller=setInterval(()=>{ loadChats(true); },5000); }
async function loadAdminBikes() { try { const data=await api('/api/admin/bikes'); state.bikes=data.bikes; const stats=[['Tổng xe',state.bikes.length],['Còn hàng',state.bikes.filter(x=>x.status==='in_stock').length],['Sắp về',state.bikes.filter(x=>x.status==='incoming').length],['Đã bán',state.bikes.filter(x=>x.status==='sold').length]]; $('#admin-stats').innerHTML=stats.map(([label,value])=>`<div class="admin-stat"><span>${esc(label)}</span><b>${value}</b></div>`).join(''); $('#admin-bikes').innerHTML=state.bikes.map(bike=>`<tr><td><span class="admin-bike-name">${esc(bike.name)}</span><span class="admin-bike-sub">${esc(bike.brand || '')} • ${esc(bike.year || '—')}</span></td><td>${categoryLabel[bike.category]}</td><td class="table-price">${bike.show_price&&Number(bike.price)?money(bike.price):'Ẩn giá'}</td><td><span class="mini-status ${esc(bike.status)}">${statusLabel[bike.status]}</span></td><td>${formatDate(bike.updated_at)}</td><td><button class="table-action" data-edit-bike="${bike.id}">Sửa</button>${owner()?` <button class="table-action table-delete" data-delete-bike="${bike.id}">Xoá</button>`:''}</td></tr>`).join('')||'<tr><td colspan="6">Chưa có xe.</td></tr>'; $$('[data-edit-bike]').forEach(btn=>btn.addEventListener('click',()=>openBikeForm(state.bikes.find(x=>x.id===Number(btn.dataset.editBike))))); $$('[data-delete-bike]').forEach(btn=>btn.addEventListener('click',()=>deleteBike(Number(btn.dataset.deleteBike)))); } catch(error){alert(error.message);} }
function openBikeForm(bike=null){
  const form=$('#bike-form'); form.reset(); $('#image-preview').innerHTML=''; $('#modal-title').textContent=bike?'Sửa thông tin xe':'Thêm xe mới'; form.elements.id.value=bike?.id||'';
  if(bike){ for(const [key,value] of Object.entries(bike)){ const field=form.elements[key]; if(!field) continue; if(field.type==='checkbox') field.checked=Boolean(value); else if(key==='images'||key==='color_variants'){} else field.value=value??''; } form.dataset.images=JSON.stringify(bike.images||[]); form.dataset.colorVariants=JSON.stringify(variantsFor(bike)); renderImagePreview(); renderColorVariants(); }
  else { form.dataset.images='[]'; form.dataset.colorVariants='[]'; form.elements.show_price.checked=true; renderColorVariants(); }
  $('#bike-message').textContent=''; openModal('bike-modal');
}
function renderImagePreview(){ const form=$('#bike-form'); const images=JSON.parse(form.dataset.images||'[]'); $('#image-preview').innerHTML=images.map((url,index)=>`<figure><img src="${esc(url)}" alt="Ảnh xe" /><button type="button" data-remove-image="${index}">×</button></figure>`).join(''); $$('[data-remove-image]').forEach(btn=>btn.addEventListener('click',()=>{ const list=JSON.parse(form.dataset.images||'[]'); list.splice(Number(btn.dataset.removeImage),1); form.dataset.images=JSON.stringify(list); renderImagePreview(); })); }
function readColorVariants(){ try { return JSON.parse($('#bike-form').dataset.colorVariants||'[]').map(item=>({name:item?.name||'',hex:item?.hex||'#7a7a7a',images:Array.isArray(item?.images)?item.images:(item?.image?[item.image]:[])})); } catch { return []; } }
function writeColorVariants(list){ $('#bike-form').dataset.colorVariants=JSON.stringify(list.slice(0,20)); renderColorVariants(); }
function renderColorVariants(){ const root=$('#color-variants'); if(!root)return; const variants=readColorVariants(); root.innerHTML=variants.length?variants.map((item,index)=>`<div class="color-variant-row" data-color-variant-row="${index}"><div class="variant-row-head"><span class="color-preview" style="--swatch:${esc(item.hex||'#7a7a7a')}"></span><label>Tên màu<input data-color-field="name" data-color-index="${index}" value="${esc(item.name||'')}" placeholder="Ví dụ: Đỏ đen" /></label><label>Màu hiển thị<input data-color-field="hex" data-color-index="${index}" type="color" value="${esc(/^#[0-9a-f]{6}$/i.test(item.hex||'')?item.hex:'#7a7a7a')}" /></label><button type="button" class="remove-color-variant" data-remove-color="${index}" aria-label="Xoá màu">×</button></div><div class="variant-photo-admin"><div class="variant-photo-grid">${item.images.map((image,imageIndex)=>`<figure><img src="${esc(image)}" alt="${esc(item.name||'Màu xe')}" /><button type="button" data-remove-color-image="${index}" data-remove-image-index="${imageIndex}" aria-label="Xoá ảnh">×</button></figure>`).join('')||'<p>Chưa có ảnh cho màu này.</p>'}</div><label class="variant-upload-button">+ Tải ảnh cho màu này<input type="file" accept="image/png,image/jpeg,image/webp,image/avif" data-color-upload="${index}" multiple /></label><small>${item.images.length}/12 ảnh</small></div></div>`).join(''):'<p class="variant-empty">Chưa thêm màu. Bấm “+ Thêm màu”, nhập tên màu rồi tải một hoặc nhiều ảnh cho đúng màu đó.</p>'; }
function addColorVariant(){ const list=readColorVariants(); if(list.length>=20){$('#bike-message').textContent='Tối đa 20 màu cho một xe.';return;} list.push({name:'',hex:'#7a7a7a',images:[]}); writeColorVariants(list); }
function handleColorVariantClick(event){ const imageButton=event.target.closest('[data-remove-color-image]'); if(imageButton){const list=readColorVariants();const item=list[Number(imageButton.dataset.removeColorImage)];if(item){item.images.splice(Number(imageButton.dataset.removeImageIndex),1);writeColorVariants(list);}return;} const button=event.target.closest('[data-remove-color]');if(!button)return; const list=readColorVariants();list.splice(Number(button.dataset.removeColor),1);writeColorVariants(list); }
async function handleColorVariantChange(event){ const input=event.target; if(input.dataset.colorUpload!==undefined){ const files=[...(input.files||[])]; if(!files.length)return; const index=Number(input.dataset.colorUpload); const message=$('#bike-message'); try { message.textContent=`Đang tải ${files.length} ảnh màu xe...`; const urls=[]; for(const file of files) urls.push(await uploadFile(file)); const list=readColorVariants(); const item=list[index]; if(item){item.images=[...new Set([...(item.images||[]),...urls])].slice(0,12); writeColorVariants(list); message.textContent=`Đã tải ${urls.length} ảnh cho màu xe.`;} } catch(error){message.textContent=error.message;} finally { input.value=''; } return; } if(!input.dataset.colorField)return; const list=readColorVariants(); const item=list[Number(input.dataset.colorIndex)];if(!item)return; item[input.dataset.colorField]=input.value; $('#bike-form').dataset.colorVariants=JSON.stringify(list); if(input.dataset.colorField==='hex'){ const dot=input.closest('.color-variant-row')?.querySelector('.color-preview');if(dot)dot.style.setProperty('--swatch',input.value); } }
async function uploadFile(file){ if(!file) return ''; if(!/^image\/(png|jpe?g|webp|avif)$/i.test(file.type))throw new Error('Chỉ nhận ảnh JPG, PNG, WEBP hoặc AVIF.'); if(file.size>8*1024*1024) throw new Error('Ảnh tối đa 8MB.'); const res=await fetch('/api/admin/upload',{method:'POST',headers:{'content-type':file.type,'x-file-name':encodeURIComponent(file.name || 'xe-may.jpg'),'x-file-size':String(file.size)},body:file}); const data=await res.json().catch(()=>({})); if(!res.ok)throw new Error(data.error||'Không tải được ảnh.'); return data.url; }
async function uploadBikeImages(files){ if(!files?.length)return; const form=$('#bike-form'); const message=$('#bike-message'); try{ message.textContent='Đang tải ảnh...'; const urls=[]; for(const file of files) urls.push(await uploadFile(file)); form.dataset.images=JSON.stringify([...JSON.parse(form.dataset.images||'[]'),...urls].slice(0,12)); renderImagePreview(); message.textContent='Đã tải ảnh.'; }catch(error){message.textContent=error.message;} }
async function saveBike(event){
  event.preventDefault(); const form=event.currentTarget; const message=$('#bike-message'); const data=Object.fromEntries(new FormData(form));
  data.featured=form.elements.featured.checked; data.show_price=form.elements.show_price.checked; data.images=JSON.parse(form.dataset.images||'[]');
  const variants=readColorVariants(); if(variants.some(item=>!item.name||!(item.images||[]).length)){message.textContent='Mỗi màu cần có tên và ít nhất một ảnh, hoặc bấm × để bỏ màu chưa hoàn thiện.';return;}
  data.color_variants=variants; if(variants.length)data.color=variants.map(item=>item.name).join(', ');
  try { const path=data.id?`/api/admin/bikes/${data.id}`:'/api/admin/bikes'; await api(path,{method:data.id?'PUT':'POST',body:JSON.stringify(data)}); closeModal('bike-modal'); await loadAdminBikes(); }catch(error){message.textContent=error.message;}
}
async function deleteBike(id){ if(!confirm('Xoá xe này? Thao tác không thể hoàn tác.'))return; try{await api(`/api/admin/bikes/${id}`,{method:'DELETE'});loadAdminBikes();}catch(error){alert(error.message);} }
async function uploadSettingImage(file){ await uploadSettingAsset(file, 'hero_image', 'Đã tải ảnh nền. Bấm Lưu thay đổi website để áp dụng.'); }
async function uploadSettingAsset(file, field, successMessage){ if(!file)return; try{ const url=await uploadFile(file); const input=$(`#settings-form [name="${field}"]`); if(input)input.value=url; $('#settings-message').textContent=successMessage;}catch(error){$('#settings-message').textContent=error.message;} }
async function loadSettingsForm(){ try{const data=await api('/api/admin/settings'); const form=$('#settings-form'); Object.entries(data.settings).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value??'';});}catch(error){alert(error.message);} }
async function saveSettings(event){ event.preventDefault(); const form=event.currentTarget; const settings=Object.fromEntries(new FormData(form)); try{ const data=await api('/api/admin/settings',{method:'PUT',body:JSON.stringify(settings)}); state.settings=data.settings; applySettings(); $('#settings-message').textContent='Đã lưu thay đổi. Website đã cập nhật.';}catch(error){$('#settings-message').textContent=error.message;} }
async function loadLeads(){ try{const data=await api('/api/admin/leads'); $('#admin-leads').innerHTML=data.leads.map(lead=>`<tr><td><span class="admin-bike-name">${esc(lead.name)}</span><span class="admin-bike-sub">${esc(lead.phone)}</span></td><td>${lead.type==='finance'?'Tư vấn trả góp':lead.type==='order'?'Đặt xe / giữ xe':'Tư vấn'}</td><td>${esc(lead.bike_name||'Chưa chọn xe')}<br><span class="admin-bike-sub">${esc(lead.down_payment||lead.note||'')}</span></td><td>${formatDate(lead.created_at)}</td></tr>`).join('')||'<tr><td colspan="4">Chưa có yêu cầu nào.</td></tr>';}catch(error){alert(error.message);} }
function openPromoForm(item=null){ const form=$('#promo-form'); form.reset(); $('#promo-modal-title').textContent=item?'Sửa khuyến mại':'Thêm chương trình'; form.elements.id.value=item?.id||''; if(item){Object.entries(item).forEach(([k,v])=>{const f=form.elements[k];if(f){if(f.type==='checkbox')f.checked=Boolean(v);else f.value=v??'';}});}openModal('promo-modal'); }
async function uploadSingleToField(file,field){try{$(field).value=await uploadFile(file);}catch(error){alert(error.message);}}
async function loadAdminPromos(){ try{const data=await api('/api/admin/promotions'); state.promotions=data.promotions; $('#admin-promos').innerHTML=data.promotions.map(item=>`<article class="admin-item-card">${item.image_url?`<img src="${esc(item.image_url)}" alt="${esc(item.title)}"/>`:'<div class="item-empty"></div>'}<div class="admin-item-card-copy"><span class="mini-status ${item.active?'in_stock':'sold'}">${item.active?'Đang áp dụng':'Tạm ẩn'}</span><h3>${esc(item.title)}</h3><p>${esc(item.description)}</p><footer><button class="table-action" data-edit-promo="${item.id}">Sửa</button>${owner()?`<button class="table-action table-delete" data-delete-promo="${item.id}">Xoá</button>`:''}</footer></div></article>`).join('')||'<div class="empty-card">Chưa có chương trình khuyến mại.</div>'; $$('[data-edit-promo]').forEach(btn=>btn.addEventListener('click',()=>openPromoForm(state.promotions.find(x=>x.id===Number(btn.dataset.editPromo))))); $$('[data-delete-promo]').forEach(btn=>btn.addEventListener('click',()=>deletePromo(Number(btn.dataset.deletePromo))));}catch(error){alert(error.message);} }
async function savePromo(event){event.preventDefault();const form=event.currentTarget;const data=Object.fromEntries(new FormData(form));data.active=form.elements.active.checked;try{await api(data.id?`/api/admin/promotions/${data.id}`:'/api/admin/promotions',{method:data.id?'PUT':'POST',body:JSON.stringify(data)});closeModal('promo-modal');loadAdminPromos();}catch(error){$('#promo-message').textContent=error.message;}}
async function deletePromo(id){if(!confirm('Xoá chương trình này?'))return;try{await api(`/api/admin/promotions/${id}`,{method:'DELETE'});loadAdminPromos();}catch(error){alert(error.message);}}
function openAccessoryForm(item=null){const form=$('#accessory-form');form.reset();$('#accessory-modal-title').textContent=item?'Sửa phụ kiện':'Thêm phụ kiện';form.elements.id.value=item?.id||'';if(item)Object.entries(item).forEach(([k,v])=>{const f=form.elements[k];if(f){if(f.type==='checkbox')f.checked=Boolean(v);else f.value=v??'';}});openModal('accessory-modal');}
async function loadAdminAccessories(){try{const data=await api('/api/admin/accessories');state.accessories=data.accessories;$('#admin-accessories').innerHTML=data.accessories.map(item=>`<article class="admin-item-card">${item.image_url?`<img src="${esc(item.image_url)}" alt="${esc(item.name)}"/>`:'<div class="item-empty"></div>'}<div class="admin-item-card-copy"><span class="accessory-category">${esc(item.category)}</span><h3>${esc(item.name)}</h3><p>${esc(item.description||'')}</p><footer><button class="table-action" data-edit-accessory="${item.id}">Sửa</button>${owner()?`<button class="table-action table-delete" data-delete-accessory="${item.id}">Xoá</button>`:''}</footer></div></article>`).join('')||'<div class="empty-card">Chưa có phụ kiện.</div>';$$('[data-edit-accessory]').forEach(btn=>btn.addEventListener('click',()=>openAccessoryForm(state.accessories.find(x=>x.id===Number(btn.dataset.editAccessory)))));$$('[data-delete-accessory]').forEach(btn=>btn.addEventListener('click',()=>deleteAccessory(Number(btn.dataset.deleteAccessory))));}catch(error){alert(error.message);}}
async function saveAccessory(event){event.preventDefault();const form=event.currentTarget;const data=Object.fromEntries(new FormData(form));data.active=form.elements.active.checked;try{await api(data.id?`/api/admin/accessories/${data.id}`:'/api/admin/accessories',{method:data.id?'PUT':'POST',body:JSON.stringify(data)});closeModal('accessory-modal');loadAdminAccessories();}catch(error){$('#accessory-message').textContent=error.message;}}
async function deleteAccessory(id){if(!confirm('Xoá phụ kiện này?'))return;try{await api(`/api/admin/accessories/${id}`,{method:'DELETE'});loadAdminAccessories();}catch(error){alert(error.message);}}
async function loadAnalytics(){try{const data=await api('/api/admin/analytics');const total=data.rows.reduce((sum,x)=>sum+Number(x.views),0),visitors=data.rows.reduce((sum,x)=>sum+Number(x.visitors),0);$('#analytics-stats').innerHTML=`<div class="admin-stat"><span>7 ngày gần đây</span><b>${total}</b></div><div class="admin-stat"><span>Khách truy cập gần đúng</span><b>${visitors}</b></div><div class="admin-stat"><span>Hôm nay</span><b>${data.rows[0]?.views||0}</b></div>`;$('#analytics-rows').innerHTML=data.rows.map(row=>`<tr><td>${esc(row.day)}</td><td>${row.views}</td><td>${row.visitors}</td></tr>`).join('')||'<tr><td colspan="3">Chưa có dữ liệu.</td></tr>';}catch(error){alert(error.message);}}
async function loadStaff(){try{const data=await api('/api/admin/staff');$('#admin-staff').innerHTML=data.staff.map(item=>`<tr><td>${esc(item.name)}</td><td>${esc(item.username)}</td><td><span class="mini-status ${item.active?'in_stock':'sold'}">${item.active?'Đang hoạt động':'Đã khoá'}</span></td><td>${formatDate(item.created_at)}</td><td><button class="table-action" data-toggle-staff="${item.id}">${item.active?'Khoá':'Mở khoá'}</button></td></tr>`).join('')||'<tr><td colspan="5">Chưa có tài khoản nhân viên.</td></tr>';$$('[data-toggle-staff]').forEach(btn=>btn.addEventListener('click',()=>toggleStaff(Number(btn.dataset.toggleStaff))));}catch(error){alert(error.message);}}
async function saveStaff(event){event.preventDefault();const form=event.currentTarget;const data=Object.fromEntries(new FormData(form));try{await api('/api/admin/staff',{method:'POST',body:JSON.stringify(data)});closeModal('staff-modal');loadStaff();}catch(error){$('#staff-message').textContent=error.message;}}
async function toggleStaff(id){try{await api(`/api/admin/staff/${id}/toggle`,{method:'POST'});loadStaff();}catch(error){alert(error.message);}}
function playBell(){try{const ctx=new (window.AudioContext||window.webkitAudioContext)();[0,.22,.44].forEach(delay=>{const oscillator=ctx.createOscillator(),gain=ctx.createGain();oscillator.frequency.value=880;gain.gain.setValueAtTime(.0001,ctx.currentTime+delay);gain.gain.exponentialRampToValueAtTime(.28,ctx.currentTime+delay+.02);gain.gain.exponentialRampToValueAtTime(.0001,ctx.currentTime+delay+.18);oscillator.connect(gain).connect(ctx.destination);oscillator.start(ctx.currentTime+delay);oscillator.stop(ctx.currentTime+delay+.19);});}catch{}}
function armChatBell(){state.chatBellEnabled=true;$('#chat-sound-button').textContent='Đã bật chuông chat';playBell();}
async function loadChats(silent=false){try{const data=await api('/api/admin/chats');state.chats=data.conversations||[];const unread=state.chats.reduce((sum,x)=>sum+Number(x.unread||0),0);const badge=$('#chat-unread-badge');badge.textContent=unread;$('.admin-tab[data-admin-view="chats"]')?.classList.toggle('has-unread',unread>0);if(silent&&state.chatBellEnabled&&unread>state.lastUnread){playBell();if(window.Notification && window.Notification.permission==='granted')new window.Notification('Tin nhắn mới từ khách',{body:'Có khách đang cần tư vấn xe.'});}state.lastUnread=unread;renderChatList();if(state.currentChat)loadChatThread(state.currentChat,true);}catch(error){if(!silent)alert(error.message);}}
function renderChatList(){const root=$('#admin-chat-list');if(!root)return;root.innerHTML=state.chats.map(item=>`<button class="admin-chat-item ${state.currentChat===item.id?'active':''}" data-chat-id="${esc(item.id)}"><strong>${esc(item.visitor_name||'Khách website')}</strong><span>${esc(item.last_message||'')}</span><small>${item.assigned_staff_name?`NV: ${esc(item.assigned_staff_name)} • `:'Chưa nhận • '}${formatDate(item.last_message_at)}${Number(item.unread)?` • ${item.unread} mới`:''}</small></button>`).join('')||'<div class="empty-thread">Chưa có tin nhắn.</div>';$$('[data-chat-id]').forEach(btn=>btn.addEventListener('click',()=>{state.currentChat=btn.dataset.chatId;renderChatList();loadChatThread(state.currentChat);}));}
async function loadChatThread(id,silent=false){try{const data=await api(`/api/admin/chats/${encodeURIComponent(id)}`);const root=$('#admin-chat-messages');root.innerHTML=(data.messages||[]).map(chatMessageMarkup).join('');root.scrollTop=root.scrollHeight;$('#admin-chat-empty').hidden=true;$('#admin-chat-form').hidden=false;const note=$('#chat-ai-note');if(note)note.textContent=data.conversation?.assigned_staff_name?`Bạn đang tư vấn với tên: ${data.conversation.assigned_staff_name}. AI chỉ gợi ý; nhân viên kiểm tra và bấm Gửi.`:'AI chỉ gợi ý; nhân viên kiểm tra và bấm Gửi.';}catch(error){if(!silent)alert(error.message);}}
async function suggestAiReply(){if(!state.currentChat)return;const button=$('#chat-ai-suggest');const field=$('#admin-chat-reply');const note=$('#chat-ai-note');button.disabled=true;button.textContent='Đang gợi ý...';try{const data=await api(`/api/admin/chat-ai-suggest/${encodeURIComponent(state.currentChat)}`,{method:'POST'});field.value=data.suggestion||'';note.textContent=data.provider==='Gemini'?'Đã có gợi ý từ Gemini — kiểm tra và chỉnh lại trước khi gửi.':`${data.provider||'Mẫu tư vấn'} — bạn có thể sửa trước khi gửi.${data.notice?' '+data.notice:''}`;field.focus();}catch(error){note.textContent=error.message;}finally{button.disabled=false;button.textContent='✦ AI gợi ý';}}
async function replyChat(event){event.preventDefault();if(!state.currentChat)return;const field=$('#admin-chat-reply'),message=field.value.trim();if(!message)return;try{await api(`/api/admin/chats/${encodeURIComponent(state.currentChat)}`,{method:'POST',body:JSON.stringify({message})});field.value='';loadChatThread(state.currentChat);loadChats(true);}catch(error){alert(error.message);}}
function formatDate(value){if(!value)return '—';const date=new Date(value.includes('T')?value:value.replace(' ','T')+'Z');return isNaN(date)?value:date.toLocaleString('vi-VN',{dateStyle:'short',timeStyle:'short'});}
document.addEventListener('keydown', event => { if (event.key === 'Escape') { const viewer=$('#gallery-viewer'); if(viewer && !viewer.hidden){ viewer.hidden=true; document.body.classList.add('modal-open'); } } });

(async function init(){ const mode=getPathMode(); if(mode==='admin'){await initAdmin();return;} if(mode==='finance'){$('#storefront').hidden=true;$('#finance-page').hidden=false;} await loadPublic(); bindPublic(); if(mode==='finance')$('#chat-widget').hidden=true; setInterval(refreshVisitorChat,12000); })();
